49: /**
50:  * {@code StreamsBuilder} provides the high-level Kafka Streams DSL to specify a Kafka Streams topology.
51:  *
52:  * <p>
53:  * It is a requirement that the processing logic ({@link Topology}) be defined in a deterministic way,
54:  * as in, the order in which all operators are added must be predictable and the same across all application
55:  * instances.
56:  * Topologies are only identical if all operators are added in the same order.
57:  * If different {@link KafkaStreams} instances of the same application build different topologies the result may be
58:  * incompatible runtime code and unexpected results or errors
59:  *
60:  * @see Topology
61:  * @see KStream
62:  * @see KTable
63:  * @see GlobalKTable
64:  */
65: public class StreamsBuilder {
66: 
67:     /** The actual topology that is constructed by this StreamsBuilder. */
68:     protected final Topology topology;
69: 
70:     /** The topology's internal builder. */
71:     protected final InternalTopologyBuilder internalTopologyBuilder;
72: 
73:     protected final InternalStreamsBuilder internalStreamsBuilder;
74: 
75:     public StreamsBuilder() {
76:         topology = new Topology();
77:         internalTopologyBuilder = topology.internalTopologyBuilder;
78:         internalStreamsBuilder = new InternalStreamsBuilder(internalTopologyBuilder, false);
79:     }
80: 
81:     /**
82:      * Create a {@code StreamsBuilder} instance.
83:      *
84:      * @param topologyConfigs    the streams configs that apply at the topology level. Please refer to {@link TopologyConfig} for more detail
85:      */
86:     @SuppressWarnings("this-escape")
87:     public StreamsBuilder(final TopologyConfig topologyConfigs) {
88:         topology = newTopology(topologyConfigs);
89:         internalTopologyBuilder = topology.internalTopologyBuilder;
90:         internalStreamsBuilder = new InternalStreamsBuilder(
91:             internalTopologyBuilder,
92:             TopologyConfig.InternalConfig.getBoolean(
93:                 topologyConfigs.originals(),
94:                 TopologyConfig.InternalConfig.ENABLE_PROCESS_PROCESSVALUE_FIX,
95:                 false
96:             )
97:         );
98:     }
99: 
100:     protected Topology newTopology(final TopologyConfig topologyConfigs) {
101:         return new Topology(topologyConfigs);
102:     }
103: 
104:     /**
105:      * Create a {@link KStream} from the specified topic.
106:      * The default {@code "auto.offset.reset"} strategy, default {@link TimestampExtractor}, and default key and value
107:      * deserializers as specified in the {@link StreamsConfig config} are used.
108:      * <p>
109:      * If multiple topics are specified there is no ordering guarantee for records from different topics.
110:      * <p>
111:      * Note that the specified input topic must be partitioned by key.
112:      * If this is not the case it is the user's responsibility to repartition the data before any key based operation
